import React, { useEffect, useState } from 'react'
import TableProvider, { useTableContext } from './Provider';
import './style.css'
import useDebounce from './useDebounce';
import InfiniteScroll from './InfiniteScroll';

export function TableHeader() {
    const { headerList } = useTableContext()
    if (headerList) {
        return (
            <thead>
                <tr>
                    {headerList.map(header => (<th key={header}>{header}</th>))}
                </tr>
            </thead>
        )
    }
}

export function TableBody() {
    const { searchedData, headerList } = useTableContext()
    if (searchedData) {
        return (
            <tbody>
                {searchedData.map(item => {
                    return <tr key={item?.id}>
                        {headerList?.map((itemKey) => <td key={itemKey}>{item[itemKey]}</td>)}
                    </tr>
                })}
            </tbody>
        )
    }
}

export function Search() {
    const { searchText, onSearchHandler } = useTableContext()
    function searchHandler(e) {
        onSearchHandler(e.target.value)
    }
    const debouncedSearch = useDebounce(searchHandler)
    return (
        <div className='search-box'>
            <input className='search-input' placeholder='Search...' name="Search" type='search' onChange={debouncedSearch} />
        </div>
    )
}

export function Table() {

    return (
        <>
            <Search />
            <InfiniteScroll>
                <table>
                    <TableHeader />
                    <TableBody />
                </table>
            </InfiniteScroll>
        </>
    )
}

function TableContainer() {
    return (
        <TableProvider>
            <Table />
        </TableProvider>
    )
}

export default TableContainer
